import { Component } from '@angular/core';
import { AuthService } from "../../../core/services/auth.service";
import { Router } from '@angular/router';

@Component({
  selector: 'app-register',
  templateUrl: './register.component.html',
  styleUrls: ['./register.component.css'],
})
export class RegisterComponent {

  name: string = '';
  password: string = '';
  email: string = '';
  dob: string = '';

  gender: string = '';
  height: number | null = null;
  weight: number | null = null;
  bloodGroup: string = '';
  mobile_no: string = '';

  knownDiseases: string[] = [];
  diseaseInput: string = '';

  // Suggestions list
  allDiseases: string[] = [
    'Diabetes',
    'Hypertension',
    'Heart Disease',
    'Asthma',
    'Arthritis',
    'Thyroid',
    'Migraine',
    'PCOS',
    'Anemia',
    'Depression'
  ];

  filteredDiseases: string[] = [];

  bloodGroups: string[] = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

  constructor(private authService: AuthService, private router: Router) {}

  // Filter suggestions
  onDiseaseInput() {
    const value = this.diseaseInput.toLowerCase();

    if (!value) {
      this.filteredDiseases = [];
      return;
    }

    this.filteredDiseases = this.allDiseases.filter(d =>
      d.toLowerCase().includes(value) &&
      !this.knownDiseases.includes(d)
    );
  }

  // Add from suggestion
  selectDisease(disease: string) {
    if (!this.knownDiseases.includes(disease)) {
      this.knownDiseases.push(disease);
    }
    this.diseaseInput = '';
    this.filteredDiseases = [];
  }

  // Add custom disease on Enter
  addDisease(event: KeyboardEvent) {
    event.preventDefault();

    const value = this.diseaseInput.trim();
    if (!value) return;

    if (!this.knownDiseases.includes(value)) {
      this.knownDiseases.push(value);
    }

    this.diseaseInput = '';
    this.filteredDiseases = [];
  }

  removeDisease(index: number) {
    this.knownDiseases.splice(index, 1);
  }

  register() {
    const data = {
      name: this.name,
      email: this.email,
      password: this.password,
      dob: this.dob,
      gender: this.gender,
      height: this.height,
      weight: this.weight,
      bloodGroup: this.bloodGroup,
      knownDiseases: this.knownDiseases,
      mobile_no: this.mobile_no,
    };

    this.authService.register(data).subscribe({
      next: () => {
        alert('Registration successful!');
        this.router.navigate(['/login']);
      },
      error: () => {
        alert('Registration failed. Please try again.');
      }
    });
  }
}
